class Solution {
public:
    string multiply(string a, string b) {
        if (a=="0"||b=="0") return "0";
        int m=a.size(), n=b.size();
        vector<int> pos(m+n,0);
        for(int i=m-1;i>=0;i--)
            for(int j=n-1;j>=0;j--){
                int mul=(a[i]-'0')*(b[j]-'0');
                int s=mul+pos[i+j+1];
                pos[i+j+1]=s%10; pos[i+j]+=s/10;
            }
        int k=0; while(k<(int)pos.size()-1&&pos[k]==0) k++;
        string res; for(;k<(int)pos.size();k++) res+=char('0'+pos[k]);
        return res;
    }
};

